#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Scheduling strategy enumeration
typedef enum {
    COST_AWARE,
    PERFORMANCE_ORIENTED,
    ENERGY_EFFICIENT,
    HYBRID
} SchedulingStrategy;

// Cloud provider structure
typedef struct {
    char name[50];
    char region[30];
    float cost_per_hour;
    float performance_score;
    float energy_efficiency;
    int available_instances;
    float reliability;
} CloudProvider;

// Workload structure
typedef struct {
    char name[50];
    int required_instances;
    float min_performance;
    float max_budget;
    SchedulingStrategy strategy;
} Workload;

// Allocation record
typedef struct {
    char workload_name[50];
    char provider_name[50];
    int instances;
    float cost;
} Allocation;

// Maximum providers and allocations
#define MAX_PROVIDERS 10
#define MAX_ALLOCATIONS 100

// Global state
CloudProvider providers[MAX_PROVIDERS];
int provider_count = 0;
Allocation allocations[MAX_ALLOCATIONS];
int allocation_count = 0;

// Function prototypes
void add_provider(const char* name, const char* region, float cost, 
                 float performance, float energy, int instances, float reliability);
CloudProvider* select_provider(Workload* workload);
bool allocate_resources(Workload* workload);
void print_allocations(void);
float calculate_score(CloudProvider* provider, Workload* workload);

// Add a cloud provider to the broker
void add_provider(const char* name, const char* region, float cost, 
                 float performance, float energy, int instances, float reliability) {
    if (provider_count >= MAX_PROVIDERS) {
        printf("Error: Maximum providers reached\n");
        return;
    }

    CloudProvider p;
    strncpy(p.name, name, 49);
    strncpy(p.region, region, 29);
    p.cost_per_hour = cost;
    p.performance_score = performance;
    p.energy_efficiency = energy;
    p.available_instances = instances;
    p.reliability = reliability;

    providers[provider_count++] = p;
    printf("[Broker] Registered provider: %s in %s\n", name, region);
}

// Calculate multi-criteria score for a provider
float calculate_score(CloudProvider* provider, Workload* workload) {
    // Normalize cost score (lower cost = higher score)
    float cost_score = (100.0f - (provider->cost_per_hour * 5.0f));
    if (cost_score < 0) cost_score = 0;

    float perf_score = provider->performance_score;
    float energy_score = provider->energy_efficiency;

    // Apply strategy-specific weights
    float total_score;
    switch (workload->strategy) {
        case COST_AWARE:
            total_score = cost_score * 0.6f + perf_score * 0.3f + energy_score * 0.1f;
            break;
        case PERFORMANCE_ORIENTED:
            total_score = perf_score * 0.6f + cost_score * 0.3f + energy_score * 0.1f;
            break;
        case ENERGY_EFFICIENT:
            total_score = energy_score * 0.5f + cost_score * 0.3f + perf_score * 0.2f;
            break;
        case HYBRID:
        default:
            total_score = (cost_score + perf_score + energy_score) / 3.0f;
            break;
    }

    return total_score;
}

// Select optimal provider based on workload requirements
CloudProvider* select_provider(Workload* workload) {
    CloudProvider* best_provider = NULL;
    float best_score = -1.0f;

    for (int i = 0; i < provider_count; i++) {
        CloudProvider* p = &providers[i];

        // Check basic requirements
        if (p->available_instances < workload->required_instances) {
            continue;
        }
        if (p->performance_score < workload->min_performance) {
            continue;
        }

        // Calculate weighted score
        float score = calculate_score(p, workload);

        if (score > best_score) {
            best_score = score;
            best_provider = p;
        }
    }

    return best_provider;
}

// Allocate resources to workload
bool allocate_resources(Workload* workload) {
    printf("\n[Broker] Processing allocation for: %s\n", workload->name);

    // Discover available resources
    printf("[Broker] Available resources:\n");
    for (int i = 0; i < provider_count; i++) {
        printf("  - %s: %d instances @ $%.2f/hr\n", 
               providers[i].name, 
               providers[i].available_instances,
               providers[i].cost_per_hour);
    }

    // Select best provider
    CloudProvider* selected = select_provider(workload);

    if (selected == NULL) {
        printf("[Broker] No suitable provider found!\n");
        return false;
    }

    // Check budget
    float estimated_cost = selected->cost_per_hour * workload->required_instances;
    if (estimated_cost > workload->max_budget) {
        printf("[Broker] Budget exceeded: $%.2f > $%.2f\n", 
               estimated_cost, workload->max_budget);
        return false;
    }

    // Allocate resources
    selected->available_instances -= workload->required_instances;

    // Record allocation
    Allocation alloc;
    strncpy(alloc.workload_name, workload->name, 49);
    strncpy(alloc.provider_name, selected->name, 49);
    alloc.instances = workload->required_instances;
    alloc.cost = estimated_cost;
    allocations[allocation_count++] = alloc;

    // Print allocation result
    printf("[Broker] Allocation successful!\n");
    printf("  Provider: %s\n", selected->name);
    printf("  Instances: %d\n", workload->required_instances);
    printf("  Cost: $%.2f/hour\n", estimated_cost);
    printf("  Remaining capacity: %d instances\n", selected->available_instances);

    return true;
}

// Print all allocations
void print_allocations(void) {
    printf("\n========== Resource Allocations ==========\n");
    for (int i = 0; i < allocation_count; i++) {
        printf("%s -> %s: %d instances ($%.2f/hr)\n",
               allocations[i].workload_name,
               allocations[i].provider_name,
               allocations[i].instances,
               allocations[i].cost);
    }
    printf("==========================================\n");
}

// Main function - Cloud Bursting Demo
int main(void) {
    printf("========================================\n");
    printf("Inter-Cloud Broker Demo\n");
    printf("========================================\n");

    // Register cloud providers
    add_provider("PrivateCloud", "us-east", 5.0f, 85.0f, 90.0f, 50, 98.0f);
    add_provider("AWS-Public", "us-east-1", 12.0f, 95.0f, 70.0f, 1000, 99.5f);
    add_provider("Azure-Public", "eastus", 10.0f, 90.0f, 75.0f, 800, 99.0f);
    add_provider("GCP-Public", "us-central1", 11.0f, 92.0f, 72.0f, 900, 99.2f);

    // Normal workload
    Workload normal = {"WebServer", 30, 70.0f, 500.0f, COST_AWARE};
    allocate_resources(&normal);

    // Peak demand workload (cloud bursting)
    Workload peak = {"HolidaySale", 250, 80.0f, 3500.0f, PERFORMANCE_ORIENTED};
    allocate_resources(&peak);

    // Batch processing workload (cost-aware)
    Workload batch = {"Analytics", 100, 60.0f, 800.0f, COST_AWARE};
    allocate_resources(&batch);

    // Green computing workload
    Workload green = {"ML-Training", 50, 75.0f, 600.0f, ENERGY_EFFICIENT};
    allocate_resources(&green);

    // Print all allocations
    print_allocations();

    printf("\nRemaining provider capacity:\n");
    for (int i = 0; i < provider_count; i++) {
        printf("  %s: %d instances\n", 
               providers[i].name, 
               providers[i].available_instances);
    }

    return 0;
}
